using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats")]
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 500;
    public int baseDamage = 10;
    public int bonusDamage = 0;
    public float critChance = 0.1f;
    public float critMultiplier = 2f;

    [Header("Shop Prices")]
    public int healthPotionPrice = 50;
    public int damageUpgradePrice = 100;
    public int fullHealPrice = 200;

    [Header("Upgrade Values")]
    public int healthPotionHealAmount = 25;
    public int damageUpgradeAmount = 5;

    public void Start()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public int CalculateDamage()
    {
        int totalDamage = baseDamage + bonusDamage;
        bool isCrit = Random.value < critChance;
        if (isCrit)
        {
            totalDamage = Mathf.RoundToInt(totalDamage * critMultiplier);
        }
        return totalDamage;
    }

    public void TakeDamage(int amount)
    {
        currentHealth -= amount;
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        if (currentHealth <= 0)
        {
            Die();
        }
    }

    public void Heal(int amount)
    {
        currentHealth += amount;
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool SpendCurrency(int amount)
    {
        if (currency < amount)
            return false;

        currency -= amount;
        return true;
    }

    public bool BuyHealthPotion()
    {
        if (!SpendCurrency(healthPotionPrice))
            return false;

        Heal(healthPotionHealAmount);
        return true;
    }

    public bool BuyDamageUpgrade()
    {
        if (!SpendCurrency(damageUpgradePrice))
            return false;

        bonusDamage += damageUpgradeAmount;
        damageUpgradePrice = CalculateNextPrice(damageUpgradePrice, 1.25f);
        return true;
    }

    public bool BuyFullHeal()
    {
        if (!SpendCurrency(fullHealPrice))
            return false;

        currentHealth = maxHealth;
        return true;
    }

    public int CalculateNextPrice(int currentPrice, float multiplier)
    {
        return Mathf.CeilToInt(currentPrice * multiplier);
    }

    private void Die()
    {
        Debug.Log("Player died.");
    }
}

public class Enemy : MonoBehaviour
{
    public int maxHealth = 50;
    public int currentHealth = 50;
    public int rewardCurrency = 25;

    public void Start()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage(int amount, PlayerStats player)
    {
        currentHealth -= amount;
        if (currentHealth <= 0)
        {
            currentHealth = 0;
            player.AddCurrency(rewardCurrency);
            Destroy(gameObject);
        }
    }
}

public class PlayerCombat : MonoBehaviour
{
    public PlayerStats playerStats;

    public void Attack(Enemy enemy)
    {
        if (enemy == null || playerStats == null)
            return;

        int damage = playerStats.CalculateDamage();
        enemy.TakeDamage(damage, playerStats);
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public bool PurchaseHealthPotion()
    {
        if (playerStats == null)
            return false;

        return playerStats.BuyHealthPotion();
    }

    public bool PurchaseDamageUpgrade()
    {
        if (playerStats == null)
            return false;

        return playerStats.BuyDamageUpgrade();
    }

    public bool PurchaseFullHeal()
    {
        if (playerStats == null)
            return false;

        return playerStats.BuyFullHeal();
    }
}